pub fn start(&self) -> Result<()> {
        info!("Starting corvia-inference server...");
        let port = self.grpc_addr.split(':').next_back().unwrap_or("8030");
        std::process::Command::new("corvia-inference")
            .arg("serve")
            .arg("--port")
            .arg(port)
            .arg("--health-probe-interval")
            .arg(self.health_probe_interval.to_string())
            .arg("--health-probe-drift-threshold")
            .arg(self.health_probe_drift_threshold.to_string())
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .spawn()
            .map_err(|e| CorviaError::Infra(format!("Failed to start corvia-inference: {e}")))?;
        info!("corvia-inference server started");
        Ok(())
    }
